    "description": "800+ particles dynamically attracted on click and repelled on hover. Features velocity-based chromatic coloring and a liquid glass cursor orb. Pure canvas performance.",
    "previewCode": "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<title>Particle Gravity Well</title>\n<style>*{margin:0;padding:0}body{background:#010103;overflow:hidden}canvas{display:block}.label{position:fixed;bottom:30px;left:50%;transform:translateX(-50%);color:rgba(0,255,170,0.4);font:700 9px/1 sans-serif;letter-spacing:.4em;text-transform:uppercase}</style>\n</head>\n<body>\n<canvas id=\"c\"></canvas>\n<div class=\"label\">Click to Pull &bull; Hover to Repel</div>\n<script>\nvar c=document.getElementById('c'),ctx=c.getContext('2d');\nvar W=c.width=window.innerWidth,H=c.height=window.innerHeight;\nvar mx=W/2,my=H/2,down=false,N=900;\nvar px=new Float32Array(N),py=new Float32Array(N),vx=new Float32Array(N),vy=new Float32Array(N),hue=new Float32Array(N);\nfor(var i=0;i<N;i++){px[i]=Math.random()*W;py[i]=Math.random()*H;vx[i]=(Math.random()-.5)*1.5;vy[i]=(Math.random()-.5)*1.5;hue[i]=140+Math.random()*80;}\nwindow.addEventListener('mousemove',function(e){mx=e.clientX;my=e.clientY;});\nwindow.addEventListener('mousedown',function(){down=true;});\nwindow.addEventListener('mouseup',function(){down=false;});\nwindow.addEventListener('resize',function(){W=c.width=window.innerWidth;H=c.height=window.innerHeight;});\nfunction draw(){\n requestAnimationFrame(draw);\n ctx.fillStyle='rgba(1,1,3,.18)';ctx.fillRect(0,0,W,H);\n for(var i=0;i<N;i++){\n var dx=mx-px[i],dy=my-py[i],d=Math.sqrt(dx*dx+dy*dy)||1;\n if(down&&d<350){var f=(350-d)/350*.9;vx[i]+=dx/d*f;vy[i]+=dy/d*f;}\n else if(!down&&d<180){var f=(180-d)/180*.6;vx[i]-=dx/d*f;vy[i]-=dy/d*f;}\n vx[i]*=.96;vy[i]*=.96;px[i]+=vx[i];py[i]+=vy[i];\n if(px[i]<0||px[i]>W)vx[i]*=-1;\n if(py[i]<0||py[i]>H)vy[i]*=-1;\n var spd=Math.sqrt(vx[i]*vx[i]+vy[i]*vy[i]);\n ctx.beginPath();ctx.arc(px[i],py[i],1+spd*.4,0,6.28);\n ctx.fillStyle='hsla('+hue[i]+',100%,'+(55+spd*5)+'%,'+(0.5+spd*.1)+')';\n ctx.fill();\n }\n var r=down?80:35,g=ctx.createRadialGradient(mx,my,0,mx,my,r);\n g.addColorStop(0,'rgba(0,255,170,.2)');g.addColorStop(.5,'rgba(0,170,255,.07)');g.addColorStop(1,'rgba(0,0,0,0)');\n ctx.beginPath();ctx.arc(mx,my,r,0,6.28);ctx.fillStyle=g;ctx.fill();\n}\ndraw();\n</script>\n</body>\n</html>",
    "code": "'use client';\nimport { useEffect, useRef } from 'react';\n\nexport const ParticleGravityWell = () => {\n const canvasRef = useRef<HTMLCanvasElement>(null);\n\n useEffect(() => {\n const c = canvasRef.current!;\n const ctx = c.getContext('2d')!;\n let W = c.width = window.innerWidth, H = c.height = window.innerHeight;\n let mx = W / 2, my = H / 2, down = false;\n const N = 900;\n const px = new Float32Array(N), py = new Float32Array(N);\n const vx = new Float32Array(N), vy = new Float32Array(N);\n const hue = new Float32Array(N);\n for (let i = 0; i < N; i++) {\n px[i] = Math.random() * W; py[i] = Math.random() * H;\n vx[i] = (Math.random() - .5) * 1.5; vy[i] = (Math.random() - .5) * 1.5;\n hue[i] = 140 + Math.random() * 80;\n }\n const onMove = (e: MouseEvent) => { mx = e.clientX; my = e.clientY; };\n const onDown = () => down = true;\n const onUp = () => down = false;\n const onResize = () => { W = c.width = window.innerWidth; H = c.height = window.innerHeight; };\n window.addEventListener('mousemove', onMove);\n window.addEventListener('mousedown', onDown);\n window.addEventListener('mouseup', onUp);\n window.addEventListener('resize', onResize);\n\n let raf: number;\n const draw = () => {\n raf = requestAnimationFrame(draw);\n ctx.fillStyle = 'rgba(1,1,3,.18)'; ctx.fillRect(0, 0, W, H);\n for (let i = 0; i < N; i++) {\n const dx = mx - px[i], dy = my - py[i], d = Math.sqrt(dx*dx+dy*dy)||1;\n if (down && d < 350) { const f=(350-d)/350*.9; vx[i]+=dx/d*f; vy[i]+=dy/d*f; }\n else if (!down && d < 180) { const f=(180-d)/180*.6; vx[i]-=dx/d*f; vy[i]-=dy/d*f; }\n vx[i] *= .96; vy[i] *= .96; px[i] += vx[i]; py[i] += vy[i];\n if (px[i] < 0 || px[i] > W) vx[i] *= -1;\n if (py[i] < 0 || py[i] > H) vy[i] *= -1;\n const spd = Math.sqrt(vx[i]*vx[i]+vy[i]*vy[i]);\n ctx.beginPath(); ctx.arc(px[i], py[i], 1+spd*.4, 0, Math.PI*2);\n ctx.fillStyle = 'hsla('+hue[i]+',100%,'+(55+spd*5)+'%,'+(0.5+spd*.1)+')';\n ctx.fill();\n }\n const r = down ? 80 : 35;\n const g = ctx.createRadialGradient(mx, my, 0, mx, my, r);\n g.addColorStop(0,'rgba(0,255,170,.2)'); g.addColorStop(.5,'rgba(0,170,255,.07)'); g.addColorStop(1,'rgba(0,0,0,0)');\n ctx.beginPath(); ctx.arc(mx, my, r, 0, Math.PI*2); ctx.fillStyle = g; ctx.fill();\n };\n draw();\n return () => {\n cancelAnimationFrame(raf);\n window.removeEventListener('mousemove', onMove);\n window.removeEventListener('mousedown', onDown);\n window.removeEventListener('mouseup', onUp);\n window.removeEventListener('resize', onResize);\n };\n }, []);\n\n return (\n <div className=\"relative w-full h-screen bg-[#010103] overflow-hidden\">\n <canvas ref={canvasRef} className=\"block w-full h-full\" />\n <div className=\"absolute bottom-8 left-1/2 -translate-x-1/2 text-[#00ffaa]/40 text-[9px] font-bold tracking-[0.4em] uppercase pointer-events-none\">\n Click to Pull &bull; Hover to Repel\n </div>\n </div>\n );\n};",
