    "description": "An interactive CSS glass grid (15x10) where hovering each cell triggers a neon glow ripple and sparkle particle burst via canvas overlay. Inspired by the Boxes and SparklesCore patterns.",
    "previewCode": "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<title>Glass Mosaic Grid</title>\n<style>\n*{margin:0;padding:0;box-sizing:border-box}\nbody{background:#010103;overflow:hidden;width:100vw;height:100vh}\ncanvas{position:fixed;inset:0;pointer-events:none;z-index:2}\n.grid{position:fixed;inset:0;display:grid;grid-template-columns:repeat(15,1fr);grid-template-rows:repeat(10,1fr);gap:1px;padding:1px;transform:skewX(-2deg) skewY(1deg)}\n.cell{background:rgba(255,255,255,.015);border:1px solid rgba(255,255,255,.04);border-radius:3px;cursor:crosshair;transition:all .25s ease;position:relative}\n.cell:hover{background:rgba(0,255,170,.09);border-color:rgba(0,255,170,.35);box-shadow:0 0 18px rgba(0,255,170,.25),inset 0 0 12px rgba(0,255,170,.08);transform:scale(1.06);z-index:5}\n.cell:nth-child(3n):hover{background:rgba(0,170,255,.09);border-color:rgba(0,170,255,.35);box-shadow:0 0 18px rgba(0,170,255,.25),inset 0 0 12px rgba(0,170,255,.08)}\n.label{position:fixed;bottom:30px;left:50%;transform:translateX(-50%);color:rgba(255,255,255,.2);font:700 9px/1 sans-serif;letter-spacing:.4em;text-transform:uppercase;z-index:10;pointer-events:none}\n</style>\n</head>\n<body>\n<div class=\"grid\" id=\"g\"></div>\n<canvas id=\"c\"></canvas>\n<div class=\"label\">Hover to Ignite</div>\n<script>\nvar g=document.getElementById('g'),c=document.getElementById('c'),ctx=c.getContext('2d');\nc.width=window.innerWidth;c.height=window.innerHeight;\nvar ps=[];\nfor(var i=0;i<150;i++){\n var d=document.createElement('div');\n d.className='cell';\n (function(el){\n el.addEventListener('mouseenter',function(){\n var r=el.getBoundingClientRect(),cx=r.left+r.width/2,cy=r.top+r.height/2;\n var h=(i%3===0)?200:140;\n for(var j=0;j<20;j++){\n var a=Math.random()*6.28,sp=1.5+Math.random()*4;\n ps.push({x:cx,y:cy,vx:Math.cos(a)*sp,vy:Math.sin(a)*sp,life:1,h:h+Math.random()*40,s:1+Math.random()*1.5});\n }\n });\n })(d);\n g.appendChild(d);\n}\nwindow.addEventListener('resize',function(){c.width=window.innerWidth;c.height=window.innerHeight;});\nfunction loop(){\n requestAnimationFrame(loop);ctx.clearRect(0,0,c.width,c.height);\n for(var i=ps.length-1;i>=0;i--){\n var p=ps[i];p.x+=p.vx;p.y+=p.vy;p.vy+=.08;p.vx*=.97;p.life-=.022;\n if(p.life<=0){ps.splice(i,1);continue;}\n ctx.beginPath();ctx.arc(p.x,p.y,p.s*p.life,0,6.28);\n ctx.fillStyle='hsla('+p.h+',100%,65%,'+p.life+')';\n ctx.shadowBlur=6;ctx.shadowColor='hsla('+p.h+',100%,65%,.8)';\n ctx.fill();\n }\n ctx.shadowBlur=0;\n}\nloop();\n</script>\n</body>\n</html>",
    "code": "'use client';\nimport { useEffect, useRef, useMemo } from 'react';\nimport { motion } from 'framer-motion';\n\ninterface Particle { x:number; y:number; vx:number; vy:number; life:number; h:number; s:number; }\n\nexport const GlassMosaicGrid = () => {\n const canvasRef = useRef<HTMLCanvasElement>(null);\n const psRef = useRef<Particle[]>([]);\n\n useEffect(() => {\n const c = canvasRef.current!;\n const ctx = c.getContext('2d')!;\n const resize = () => { c.width = window.innerWidth; c.height = window.innerHeight; };\n resize();\n window.addEventListener('resize', resize);\n let raf: number;\n const loop = () => {\n raf = requestAnimationFrame(loop);\n ctx.clearRect(0, 0, c.width, c.height);\n const ps = psRef.current;\n for (let i = ps.length - 1; i >= 0; i--) {\n const p = ps[i]; p.x+=p.vx; p.y+=p.vy; p.vy+=.08; p.vx*=.97; p.life-=.022;\n if (p.life <= 0) { ps.splice(i, 1); continue; }\n ctx.beginPath(); ctx.arc(p.x, p.y, p.s*p.life, 0, Math.PI*2);\n ctx.fillStyle = 'hsla('+p.h+',100%,65%,'+p.life+')';\n ctx.shadowBlur = 6; ctx.shadowColor = 'hsla('+p.h+',100%,65%,.8)';\n ctx.fill();\n }\n ctx.shadowBlur = 0;\n };\n loop();\n return () => { cancelAnimationFrame(raf); window.removeEventListener('resize', resize); };\n }, []);\n\n const cells = useMemo(() => Array.from({ length: 150 }, (_, i) => i), []);\n\n const handleEnter = (e: React.MouseEvent<HTMLDivElement>, i: number) => {\n const r = e.currentTarget.getBoundingClientRect();\n const cx = r.left + r.width/2, cy = r.top + r.height/2;\n const h = i % 3 === 0 ? 200 : 140;\n for (let j = 0; j < 20; j++) {\n const a = Math.random()*Math.PI*2, sp = 1.5+Math.random()*4;\n psRef.current.push({ x:cx, y:cy, vx:Math.cos(a)*sp, vy:Math.sin(a)*sp, life:1, h:h+Math.random()*40, s:1+Math.random() });\n }\n };\n\n return (\n <div className=\"relative w-full h-screen bg-[#010103] overflow-hidden\">\n <div className=\"absolute inset-[1px] grid gap-[1px]\" style={{gridTemplateColumns:'repeat(15,1fr)',gridTemplateRows:'repeat(10,1fr)',transform:'skewX(-2deg) skewY(1deg)'}}>\n {cells.map(i => (\n <motion.div key={i} onMouseEnter={e => handleEnter(e, i)}\n className=\"bg-white/[0.015] border border-white/[0.04] rounded-sm cursor-crosshair\"\n whileHover={{ scale: 1.06, backgroundColor: i%3===0 ? 'rgba(0,170,255,0.09)' : 'rgba(0,255,170,0.09)' }}\n transition={{ duration: .2 }} />\n ))}\n </div>\n <canvas ref={canvasRef} className=\"absolute inset-0 pointer-events-none z-10\" />\n <div className=\"absolute bottom-8 left-1/2 -translate-x-1/2 text-white/20 text-[9px] font-bold tracking-[0.4em] uppercase pointer-events-none z-20\">\n Hover to Ignite\n </div>\n </div>\n );\n};",
    "prompt": "Create a full-screen glass mosaic grid background (15 columns x 10 rows) with 1px gap. Each cell has a subtle glass appearance (white/1.5% bg, white/4% border, 3px radius). On hover, cells glow with neon (alternating cyan and emerald) with scale(1.06). A canvas overlay renders sparkle particle bursts (20 particles per hover) that emit from cell centers with gravity, fade out, and have neon coloring matching the cell variant. Entire grid is slightly skewed (skewX -2deg, skewY 1deg) for depth. Background #010103.",
