    "code": "/* Infinite Nebula Tunnel • Three.js */\nconst geometry = new THREE.CylinderGeometry(10, 10, 100, 64, 64, true);\nconst material = new THREE.ShaderMaterial({\n side: THREE.BackSide,\n uniforms: { uTime: { value: 0 }, uMouse: { value: new THREE.Vector2() } },\n vertexShader: `varying vec2 vUv; void main() { vUv = uv; gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0); }`,\n fragmentShader: `\n varying vec2 vUv;\n uniform float uTime;\n void main() {\n vec2 uv = vUv;\n uv.y += uTime * 0.1;\n float n = sin(uv.x * 20.0 + uTime) * sin(uv.y * 20.0);\n vec3 col1 = vec3(0.1, 0.0, 0.3); vec3 col2 = vec3(0.0, 0.5, 0.8);\n vec3 final = mix(col1, col2, n * 0.5 + 0.5);\n float glow = pow(1.0 - abs(vUv.x - 0.5) * 2.0, 3.0);\n gl_FragColor = vec4(final * glow, 1.0);\n }`\n});",
